func run(conn net.Conn) {
	reader := bufio.NewReader(conn)
	conn.Write([]byte("Enter coeff:s, one per line. End with empty line\n"))
	i := 0
	isCorrect := true
	for {
		l, err := reader.ReadString('\n')
		if err != nil {
			conn.Write([]byte("couldn't read\n"))
			_ = conn.Close()
			return
		}
		l = strings.Trim(l, " \t\r\n")
		if len(l) == 0 {
			break
		}
		if l != correct[i] {
			isCorrect = false
		}
		if i < len(correct)-1 {
			i++
		}
	}
	if isCorrect && i == len(correct)-1 {
		conn.Write([]byte("Good job!"))
		conn.Write([]byte(the_flag))
		conn.Write([]byte("\n"))
	} else {
		conn.Write([]byte("Try again\n"))
	}
	_ = conn.Close()
}

func main() {
	ln, err := net.Listen("tcp", "0.0.0.0:34567")
	if err != nil {
		fmt.Println("failed to bind")
		fmt.Println(err)
		return
	}
	fmt.Println("Listener started")
	for {
		conn, err := ln.Accept()
		if err != nil {
			fmt.Println("failed to accept")
			fmt.Println(err)
			continue
		}
		go run(conn)
	}
}
